from board import Board

def prompt_user_for_move():
    # Get user input for moves
    move = input("Enter your move (e.g., a1-b2): ")
    return move

def run_game():
    board = Board()
    current_turn = "white"

    while True:
        print(board)
        move = prompt_user_for_move()
        # Parse and validate the move
        start, end = move.split("-")
        if board.is_valid_move(start, end):
            board.make_move(start, end)
            if current_turn == "white":
                current_turn = "black"
            else:
                current_turn = "white"
        else:
            print("Invalid move. Try again.")
